cd C:\Users\edburns\workareas\BRK206-00
$REPO="edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR=23
$TIMEOUT=600
$INTERVAL=30
$ELAPSED=0
$FOUND=""

while ($ELAPSED -lt $TIMEOUT) {
  $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" 2>$null | ConvertFrom-Json

  # Strategy A
  $a = $reviews | Where-Object { $_.body -match "Copilot.s findings" }
  if ($a) { $FOUND = "Strategy A"; break }

  # Strategy B
  $b = $reviews | Where-Object { $_.body -match "Pull request overview" }
  if ($b) { $FOUND = "Strategy B"; break }

  # Strategy C
  $c = $reviews | Where-Object { $_.user.login -match "copilot-pull-request-reviewer" }
  if ($c) { $FOUND = "Strategy C"; break }

  # Strategy D - line comments
  $comments = gh api "/repos/$REPO/pulls/$PR/comments" 2>$null | ConvertFrom-Json
  $d = $comments | Where-Object { $_.user.login -eq "Copilot" }
  if ($d) { $FOUND = "Strategy D"; break }

  Write-Host "Elapsed: $ELAPSED s — no review yet, waiting $INTERVAL s..."
  Start-Sleep -Seconds $INTERVAL
  $ELAPSED += $INTERVAL
}

if ($FOUND) { 
  Write-Host "Review found via: $FOUND"
  gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | {id: .id, user: .user.login, state: .state, body_preview: (.body[0:500])}'
} else { 
  Write-Host "TIMEOUT: No Copilot review posted within $TIMEOUT seconds" 
}

